import type { Ref } from "react";
import { cn } from "../../lib/utils";
import { ListItemBase } from "./ListItemBase";
import { ListItemRef, ListItemType } from "../../types/list";

// ============================================================================
// TYPES
// ============================================================================

export interface ConversationListItemProps {
  /**
   * Unique key for the list item
   */
  itemKey: string;

  /**
   * Conversation content - can be a string or a custom element (e.g. input for inline editing)
   */
  content: React.ReactNode;

  /**
   * Whether the item is currently selected
   */
  selected?: boolean;

  /**
   * Whether the content should render in bold (e.g. pinned conversations)
   * @default false
   */
  bold?: boolean;

  /**
   * Optional click handler
   */
  onClick?: () => void;

  /**
   * Custom action buttons to display on hover/focus
   */
  actions?: React.ReactNode;

  /**
   * Additional CSS classes
   */
  className?: string;
}

// ============================================================================
// MAIN COMPONENT
// ============================================================================

/**
 * ConversationListItem - A specialized list item for displaying conversations
 * with flexible content (text or custom elements) and customizable action buttons.
 *
 * @example
 * ```tsx
 * // Simple text content
 * <ConversationListItem
 *   itemKey="conv-1"
 *   content="Cash Flow Improvement"
 *   selected
 *   actions={
 *     <>
 *       <Button iconOnly icon={<RotateCwIcon />} onClick={...} />
 *       <Button iconOnly icon={<OverflowIcon />} onClick={...} />
 *     </>
 *   }
 * />
 *
 * // Editable content with input
 * <ConversationListItem
 *   itemKey="conv-2"
 *   content={
 *     <input
 *       type="text"
 *       value={title}
 *       onChange={...}
 *       className="w-full bg-transparent outline-none"
 *     />
 *   }
 * />
 * ```
 */
export function ConversationListItem({
      itemKey,
      content,
      selected = false,
      bold = false,
      onClick,
      actions,
      className,
      ref,
    }: ConversationListItemProps & { ref?: Ref<ListItemRef> }) {
    const isStringContent = typeof content === 'string';

    return (
      <ListItemBase
        ref={ref}
        itemKey={itemKey}
        type={ListItemType.Active}
        selected={selected}
        onClick={onClick}
        className={cn(
          "group px-4 py-0",
          selected && "!bg-sapphire-brand-background/10",
          className
        )}
      >
        {({ isFocused, isFocusedWithin }) => (
          <div className="flex items-center gap-2 w-full min-w-0">
            {/* Content */}
            <div className="flex-1 min-w-0">
              <div className={cn(
                "text-sm",
                isStringContent && "truncate",
                selected
                  ? "font-semibold text-sapphire-brand-foreground"
                  : bold
                    ? "font-bold text-sapphire-text-primary group-hover:text-sapphire-brand-foreground"
                    : "font-normal text-sapphire-text-primary group-hover:text-sapphire-brand-foreground"
              )}>
                {content}
              </div>
            </div>

            {/* Action buttons - show on hover, when selected, or when focus is within */}
            {actions && (
              <div className={cn(
                "shrink-0 flex items-center gap-1 transition-opacity",
                (selected || isFocused || isFocusedWithin)
                  ? "visible opacity-100 relative"
                  : "invisible opacity-0 absolute group-hover:visible group-hover:opacity-100 group-hover:relative"
              )}>
                {actions}
              </div>
            )}
          </div>
        )}
      </ListItemBase>
    );
  }
